def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.8:
            score = (1 - ratio) ** 3 + 0.2
        elif 0.5 < ratio <= 0.8:
            score = np.exp(-(ratio * 10)) + 0.1
        else:
            for k in range(1, 6):
                score += ((-1) ** k) * (ratio ** (k + 1)) / (k * 1.5)
            score = abs(score) + 0.05
        neighbors_influence = 0.0
        for offset in range(1, 5):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / offset
                    neighbors_influence += diff_ratio * weight * 0.07
        capacity_factor = np.sqrt(capacity)
        if capacity_factor == 0:
            capacity_factor = 1
        priority = score + neighbors_influence / capacity_factor
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 5
    return priorities
